mkdir -p docs && touch docs/.nojekyll && cp -r src/web/* docs/ 2>/dev/null || true && node --input-type=commonjs -p "var p=require('./package.json');['name','version','description'].map(function(k){return 'export const '+k+' = '+JSON.stringify(p[k])+';'}).join('\n')" > docs/lib-meta.js && node -e 'const fs=require('fs');const path=require('path');fs.mkdirSync('docs',{recursive:true});fs.writeFileSync(path.join('docs','lib-browser.js'),`// docs/lib-browser.js
// Generated browser-compatible module exposing the hamming functions.

export function hammingDistance(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') {
    throw new TypeError('Both arguments must be strings');
  }
  const ra = Array.from(a);
  const rb = Array.from(b);
  if (ra.length !== rb.length) {
    throw new RangeError('Strings must have the same length in code points');
  }
  let count = 0;
  for (let i = 0; i < ra.length; i++) {
    if (ra[i] !== rb[i]) count++;
  }
  return count;
}

export function hammingDistanceBits(x, y) {
  const isBigIntX = typeof x === 'bigint';
  const isBigIntY = typeof y === 'bigint';
  if (!isBigIntX && typeof x !== 'number') throw new TypeError('x must be a number or bigint');
  if (!isBigIntY && typeof y !== 'number') throw new TypeError('y must be a number or bigint');

  if (!isBigIntX) {
    if (!Number.isInteger(x)) throw new TypeError('x must be an integer');
    if (x < 0) throw new RangeError('Integers must be non-negative');
  }
  if (!isBigIntY) {
    if (!Number.isInteger(y)) throw new TypeError('y must be an integer');
    if (y < 0) throw new RangeError('Integers must be non-negative');
  }

  const bx = isBigIntX ? x : BigInt(x);
  const by = isBigIntY ? y : BigInt(y);
  if (bx < 0n || by < 0n) throw new RangeError('Integers must be non-negative');

  let v = bx ^ by;
  let count = 0;
  while (v) {
    count += Number(v & 1n);
    v = v >> 1n;
  }
  return count;
}
`);
